import { Registry } from "../../core/zc-registry";

const geoLocation2 = (size) => {
    return {
        outer:
            `${'M' + ' '}${0} ${size * -1}C` +
            ` ${size * -0.1933} ${size * -1} ${size * -0.35} ${size * -0.8433} ${size * -0.35} ${size * -0.65}C` +
            ` ${size * -0.35} ${size * -0.31} ${size * -0.0233} ${size * -0.0167} ${size * -0.01} ${size * -0.0033}C` +
            ` ${size * -0.0067} ${0} ${size * -0.0033} ${0} ${0} ${0}S` +
            ` ${size * 0.0067} ${0} ${size * 0.01} ${size * -0.0033}C` +
            ` ${size * 0.0233} ${size * -0.0167} ${size * 0.35} ${size * -0.31} ${size * 0.35} ${size * -0.65}C` +
            ` ${size * 0.35} ${size * -0.8433} ${size * 0.1933} ${size * -1} ${0} ${size * -1}z`,
        inner:
            `${'M' + ' '}${0} ${size * -1.6667}C` +
            ` ${size * 0.2} ${size * -1.6667} ${size * 0.3667} ${size * -1.5} ${size * 0.3667} ${size * -1.3}S` +
            ` ${size * 0.2} ${size * -0.9333} ${0} ${size * -0.9333}S` +
            ` ${size * -0.3667} ${size * -1.1} ${size * -0.3667} ${size * -1.3}S` +
            ` ${size * -0.2} ${size * -1.6667} ${0} ${size * -1.6667}z`
    }
};
Registry.getComponent('svg.symbols.constants')['geo-location-2'] = geoLocation2;
export default geoLocation2;